import{o as p,c as e,D as t}from"./framework.54301fec.js";const a='{"title":"Глава 11","description":"","frontmatter":{"title":"Глава 11","subtitle":"Малини виджайоттара тантра","tags":"malini","date":"2020-08-30T00:00:00.000Z"},"headers":[{"level":2,"title":"Одиннадцатая глава","slug":"одиннадцатая-гnава"}],"relativePath":"texts/malini-vijayottara/11.md","lastUpdated":1624912921154}',r={},l=t('<h2 id="одиннадцатая-гnава"><a class="header-anchor" href="#одиннадцатая-гnава" aria-hidden="true">#</a> Одиннадцатая глава</h2><p>Теперь поведаю о дикше, самой труднодостижимой. Творящей наслаждение и Освобождение, творящей прямое видение ..1.</p><p>Для нее не нужны никакие мандалы, жертвенные ямы и прочее. Перед ней не (выполняется) ньяса и прочее, а омовение - по желанию ..2.</p><p>Войдя в место жертвоприношения, хорошо умащенное, почитаемое, обратившись лицом на восток или на север облаченный в прекрасные цветы ..3.</p><p>Созерцая сияющую Шакти от стоп до головы, следует созерцать сгорающее тело посредством махамудры ..4.</p><p>В порядке анулома следует созерцать малини, являющую амриту, ради нисхождения ее в тело. Эта дхьяна выполняется в уме ..5.</p><p>Затем следует созерцать, как было описано ранее, очищение адхв в теле. Затем, очистив предметы, следует вести (Кундалини) Шакти к амрите ..6.</p><p>Во всех обрядах знающий ритуал должен жертвовать Малини, пребывающей в середине высшей сферы, или всей высшей (сфере) целиком, о Возлюбленная!.7.</p><p>В начале следует почитать Ганешу для устранения препятствий. Затем, приступив к (почитанию) своего гуру, следует почитать семью гуру ..8.</p><p>После Ганеши следует почтить все множество мантр, их владыкам следует поднести аргхью ..9.</p><p>По окончании следует почитать Видью. Эта Видья есть Махешвари. После (почитания) мантры, видьи и Ганеши следует наполниться кула Шакти ..10.</p><p>На восточном, южном и северном направлении почитаются четыре Махешвари и прочие: находящиеся, начиная с востока и заканчивая северо-востоком, Индрани и прочие ..11.</p><p>Выше следует почитать Бога в форме кута (КША), и Ану мантры, дживу в форме палки, дживу пребывающую в вверху трезубца ..12.</p><p>Правый большой палец внизу, затем левая грудь, после него живот, горло, украшенные левым зубцом ..13.</p><p>Затем Шива и язык, над ним - верхняя челюсть. Так образуется царь над йогини чакрами ..14. (<em>Описывается мантра, к сожалению, не удалось расшифровать</em>)</p><p>Благодаря его произнесению является высшее сознание. Затем следует жертвовать, согласно правилу, восьмерке героев вместе с (их) Шакти ..15.</p><p>Желая различных могуществ, следует представить вначале образ Шри, вплоть до стоп, вместе с гандхой, дхупой и прочим ..16.</p><p>Затем, призвав ученика многократно и хорошо испытанного, окропив (при помощи) Рудра Шакти, следует поместить его перед божеством ..17.</p><p>Оглядев свои ладони следует освятить их рудра Шакти. Затем следует поднести цветы с рук с благовониями по сторонам света ..18.</p><p>Созерцая их безопорно, следует созерцать их как наполненные Шакти. Сжав их с шакти мантрой и нетрой, следует (поднести)их к глазам, как и ранее ..19.</p><p>Следует поместить (в них) цветок. Это - Шакти пребывающая в руке. Куда упадет цветок, там будет обозначена Кула ..20.</p><p>Затем его следует поднести к лицу и бросить к ногам (ученика). Затем у его головы почитая чакру (образованную) руками, знающий йогу пусть пропустит Шакти (через руки), пока она не войдет в голову (ученика). Это именуется правилом «руки Шивы», творящим прямое видение ..21-22.</p><p>Затем следует поднести горшок, наполненный плодами миробала и т.д .. Сделав тело поддерживаемым Шакти, следует поставить перед собой ученика ..23.</p><p>Одновременно с бросанием цветов правой рукой и произнесением мантры, следует взять горшок, пребывая умом в созерцании ..24.</p><p>Посредством «руки Шивы», следует подняв поднести ее к лицу. С этим ритуалом подносится (сосуд), сделанный из дерева баньян ..25.</p><p>Следует поднести зубочитску, о Деви, размером 16 ангул. Из всего приходящего произносящий мантру (гуру) не раздумывая должен выбрать (разновидность) шактипату;.26.</p><p>Который подразделяется на медленный, умеренный и пр. Мудрый (должен выбрать разновидность): медленный, умеренный и др. Это именуется самая дикшей, производимой описанным выше утвердившимся (в ней) ..27.</p><p>Когда желающий получить дикшу, жертвует (все) в уме, желая этого, как и раньше по порядку, йогин, почтив Владыку Кулы должен с нежность вглядеться и осмотреть ученика, созерцая усердно Шакти от стоп до головы;.28-29.</p><p>Размещая очищаемые адхвы, созерцая проникновение во все адхвы, посредством описанной ранее шакти таттвы и прочего. Войдя в него, следует выполнить этот обряд. Посредством очищения корня, начинается очищение светом огня Шакти ..30-31.</p><p>(Затем) следует соединить очищаемое с чистым, пребывая умом в созерцании. Так все (адхвы) очищаются, сжигаемые несравненным (огнем) ..32.</p><p>Следует созерцать как они растворяются в Шиве, нишкале или в сакале. Посредством йоги соединяясь на пути со своим почитаемым источником ..33.</p><p>Выполняется сжигание цветка, отделенного от своего источника. Благодаря этому, великомудрый, очищается мышление ученика ..34.</p><p>Следует отметить признаки погружения (сознания) ананда и др посредством почитания. (Это) - ананда, удбхава, камйа, нидра и гхурни - пятая ..35.</p><p>Наделенный (такими видами) шакти (паты) подразделяемыми на медленную, умеренную и т.д. он может сбросить оковы и принять оковы по своему желанию ..36.</p><p>Приняв их, он может их разъединить для особого наслаждения. Ни для кого иного не является эта «одержимость» ..37.</p><p>Посредством шакти он сможет сжечь их снаружи и внутри. Они сжигаются в нем, как дерево с отсеченными корнями ..38. [small]Такова в священной «Малини виджайоттара тантре» одиннадцатая глава.[/small]</p>',36);r.render=function(t,a,r,i,s,n){return p(),e("div",null,[l])};export default r;export{a as __pageData};
